<script>
  let menuLocale = 'en';

  if (menuLocale == 'en') {
    menuLocale = 'en-US';
  }

  function mountHeader(data = false) {
    const headerTarget = document.getElementById('header');
    if (!headerTarget) {
      return;
    }
    let options = {
      baseURL: window.location.origin,
      signedIn: false,
      locale: menuLocale
    };

    if (data) {
      options.secondaryMenu = data;
    }

    options.showMembershipCardLink = true;

    new NVDeveloperHeader({
      target: headerTarget,
      props: options
    });
  }

  function mountFooter(data = false) {
    const footerTarget = document.getElementById('footer');
    if (!footerTarget) {
      return;
    }
    let options = {
      menu: data,
      locale: menuLocale
    };

    new NVDeveloperFooter({
      target: document.getElementById('footer'),
      props: options
    });
  }

  let url = 'd29g4g2dyqv443.cloudfront.net';
  let headerMenuURL = "https://d29g4g2dyqv443.cloudfront.net/menu/en-US/header-secondary.json";

  if (headerMenuURL) {
    fetch(headerMenuURL)
      .then(response => response.json())
      .then(data => {
        mountHeader(data);
      })
      .catch((error) => {
        mountHeader();
        window.nv.tracing.addError('menu', error);
      });
  } else {
    mountHeader();
  }

  fetch(`https://${url}/menu/${menuLocale}/footer.json`)
    .then(response => response.json())
    .then(data => {
      mountFooter(data);
    })
    .catch((error) => {
      mountFooter();
      window.nv.tracing.addError('menu', error);
    });
</script>

