        }
    });
    observer.observe(root, { childList: true, subtree: true });
}

// Terminal Window
document.addEventListener('click', function(e) {
    if (e.target.closest('#home-hero-terminal')) {
        track(e.target, 'event10', 'link:hero:terminal:', 'install copy window');
    }
});
</script>
